SELECT feedback_date, comments
FROM weapon_feedback
WHERE weapon_id = 1;

SELECT weapon_id, AVG(total_damage_dealt) AS average_total_damage
FROM weapon_feedback
GROUP BY weapon_id;

SELECT rarity, COUNT(*) AS weapon_count
FROM weapons
GROUP BY rarity;

SELECT SUM(total_damage) AS total_damage_dealt
FROM weapon_usage
WHERE weapon_id = 0;

SELECT AVG(rating) AS average_rating
FROM weapon_feedback
WHERE weapon_id = 0;
